<?php
namespace App\Http\Requests\Admin;
use Illuminate\Foundation\Http\FormRequest;
class BookingRequest extends FormRequest { public function authorize(): bool { return $this->user()->can('manage', \App\Models\Booking::class); } public function rules(): array { return ['agent_id'=>'nullable|exists:agents,id','travel_schedule_id'=>'required|exists:travel_schedules,id','return_schedule_id'=>'nullable|exists:travel_schedules,id','seat_ids'=>'required|array|min:1','seat_ids.*'=>'integer|exists:seats,id','hold_token'=>'nullable|string','first_name'=>'required|max:255','last_name'=>'required|max:255','gender'=>'required|in:male,female,other','dob'=>'nullable|date|before:today','nationality_id'=>'nullable|exists:nationalities,id','passport'=>'nullable|max:100','national_id'=>'nullable|max:100','contact_number'=>'required|max:50','return_date'=>'nullable|date']; } }
